"use strict";(self.webpackChunksysanalyst_kb=self.webpackChunksysanalyst_kb||[]).push([["21480"],{1408(i){i.exports=JSON.parse('{"tag":{"label":"logistics","permalink":"/sysanalyst-kb.github.io/docs/tags/logistics","allTagsPath":"/sysanalyst-kb.github.io/docs/tags","count":10,"items":[{"id":"specialization/logistics-tms","title":"TMS \u2014 \u0441\u0438\u0441\u0442\u0435\u043C\u0430 \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F \u043F\u0435\u0440\u0435\u0432\u043E\u0437\u043A\u0430\u043C\u0438","description":"TMS (Transportation Management System) \u2014 \u0441\u0438\u0441\u0442\u0435\u043C\u0430 \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F \u043F\u0435\u0440\u0435\u0432\u043E\u0437\u043A\u0430\u043C\u0438. \u041F\u043E\u043A\u0440\u044B\u0432\u0430\u0435\u0442 SAP TM, Oracle OTM, \u042F\u043D\u0434\u0435\u043A\u0441.\u041C\u0430\u0440\u0448\u0440\u0443\u0442\u0438\u0437\u0430\u0446\u0438\u044F, 1\u0421 $5B+ \u0433\u043B\u043E\u0431\u0430\u043B\u044C\u043D\u043E \u0434\u043B\u044F TMS-\u0441\u0438\u0441\u0442\u0435\u043C.","permalink":"/sysanalyst-kb.github.io/docs/specialization/logistics-tms"},{"id":"specialization/logistics-analytics","title":"\u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0430 \u0432 \u043B\u043E\u0433\u0438\u0441\u0442\u0438\u043A\u0435","description":"\u041B\u043E\u0433\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0430 \u2014 \u0441\u0438\u0441\u0442\u0435\u043C\u0430 \u043C\u0435\u0442\u0440\u0438\u043A \u0434\u043B\u044F \u043E\u043F\u0435\u0440\u0430\u0446\u0438\u043E\u043D\u043D\u043E\u0433\u043E \u043A\u043E\u043D\u0442\u0440\u043E\u043B\u044F \u0438 \u0441\u0442\u0440\u0430\u0442\u0435\u0433\u0438\u0447\u0435\u0441\u043A\u043E\u0439 \u043E\u043F\u0442\u0438\u043C\u0438\u0437\u0430\u0446\u0438\u0438 ClickHouse + Superset, Redash, Tableau.","permalink":"/sysanalyst-kb.github.io/docs/specialization/logistics-analytics"},{"id":"specialization/logistics-last-mile","title":"\u0414\u043E\u0441\u0442\u0430\u0432\u043A\u0430 \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0435\u0439 \u043C\u0438\u043B\u0438 \u0438 \u0442\u0440\u0435\u043A\u0438\u043D\u0433","description":"\u041F\u043E\u0441\u043B\u0435\u0434\u043D\u044F\u044F \u043C\u0438\u043B\u044F \u2014 \u0444\u0438\u043D\u0430\u043B\u044C\u043D\u044B\u0439 \u044D\u0442\u0430\u043F \u0434\u043E\u0441\u0442\u0430\u0432\u043A\u0438 \u043E\u0442 \u0441\u043A\u043B\u0430\u0434\u0430/\u0445\u0430\u0431\u0430/\u041F\u0412\u0417 \u0434\u043E \u043A\u043B\u0438\u0435\u043D\u0442\u0430. \u0421\u0430\u043C\u044B\u0439 \u0434\u043E\u0440\u043E\u0433\u043E\u0439 (40-60% \u0441\u0442\u043E\u0438\u043C\u043E\u0441\u0442\u0438 \u043B\u043E\u0433\u0438\u0441\u0442\u0438\u043A\u0438) \u0438 \u043A\u043B\u0438\u0435\u043D\u0442\u043E\u043E\u0440\u0438\u0435\u043D\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u044B\u0439 \u044D\u0442\u0430\u043F. \u041A\u043B\u044E\u0447\u0435\u0432\u044B\u0435 \u0430\u0441\u043F\u0435\u043A\u0442\u044B \u042F\u043D\u0434\u0435\u043A\u0441.\u0414\u043E\u0441\u0442\u0430\u0432\u043A\u0430 (100K+ \u0437\u0430\u043A\u0430\u0437\u043E\u0432/\u0434\u0435\u043D\u044C), \u0421\u0414\u042D\u041A, Boxberry, 5Post.","permalink":"/sysanalyst-kb.github.io/docs/specialization/logistics-last-mile"},{"id":"specialization/logistics-integrations","title":"\u0418\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u0438 \u0441 \u043C\u0430\u0440\u043A\u0435\u0442\u043F\u043B\u0435\u0439\u0441\u0430\u043C\u0438 \u0438 \u043A\u0443\u0440\u044C\u0435\u0440\u0430\u043C\u0438","description":"\u041B\u043E\u0433\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u043F\u043B\u0430\u0442\u0444\u043E\u0440\u043C\u0430 \u0438\u043D\u0442\u0435\u0433\u0440\u0438\u0440\u0443\u0435\u0442\u0441\u044F \u0441 \u0434\u0435\u0441\u044F\u0442\u043A\u0430\u043C\u0438 \u0432\u043D\u0435\u0448\u043D\u0438\u0445 \u0441\u0435\u0440\u0432\u0438\u0441\u043E\u0432 \u0430\u0441\u0438\u043D\u0445\u0440\u043E\u043D\u043D\u043E\u0441\u0442\u044C (Webhook + Polling), \u043E\u0431\u0440\u0430\u0431\u043E\u0442\u043A\u0430 \u043E\u0448\u0438\u0431\u043E\u043A, \u0440\u0435\u0442\u0440\u0430\u0438, \u0438\u0434\u0435\u043C\u043F\u043E\u0442\u0435\u043D\u0442\u043D\u043E\u0441\u0442\u044C.","permalink":"/sysanalyst-kb.github.io/docs/specialization/logistics-integrations"},{"id":"specialization/logistics-path","title":"\u041B\u043E\u0433\u0438\u0441\u0442\u0438\u043A\u0430 \u2014 \u0440\u043E\u043B\u044C, \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u043A\u0430, \u043A\u0430\u0440\u044C\u0435\u0440\u043D\u044B\u0439 \u043F\u0443\u0442\u044C","description":"\u041B\u043E\u0433\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0439 \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u0441 \u0441\u0438\u0441\u0442\u0435\u043C\u0430\u043C\u0438 \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F \u043F\u0435\u0440\u0435\u0432\u043E\u0437\u043A\u0430\u043C\u0438 (TMS), \u0441\u043A\u043B\u0430\u0434\u0430\u043C\u0438 (WMS), \u0434\u043E\u0441\u0442\u0430\u0432\u043A\u043E\u0439 \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0435\u0439 \u043C\u0438\u043B\u0438, \u043C\u0430\u0440\u0448\u0440\u0443\u0442\u0438\u0437\u0430\u0446\u0438\u0435\u0439 (VRP) \u0438 \u042D\u0414\u041E. \u0421\u043F\u0435\u0446\u0438\u0444\u0438\u043A\u0430 $500B+ \u0433\u043B\u043E\u0431\u0430\u043B\u044C\u043D\u043E, 5M+ \u043F\u0435\u0440\u0435\u0432\u043E\u0437\u043E\u043A/\u0434\u0435\u043D\u044C \u0432 \u0420\u0424.","permalink":"/sysanalyst-kb.github.io/docs/specialization/logistics-path"},{"id":"specialization/logistics-routing","title":"\u041C\u0430\u0440\u0448\u0440\u0443\u0442\u0438\u0437\u0430\u0446\u0438\u044F \u0438 \u043E\u043F\u0442\u0438\u043C\u0438\u0437\u0430\u0446\u0438\u044F","description":"\u041C\u0430\u0440\u0448\u0440\u0443\u0442\u0438\u0437\u0430\u0446\u0438\u044F \u2014 \u043F\u043E\u0441\u0442\u0440\u043E\u0435\u043D\u0438\u0435 \u043E\u043F\u0442\u0438\u043C\u0430\u043B\u044C\u043D\u044B\u0445 \u043C\u0430\u0440\u0448\u0440\u0443\u0442\u043E\u0432 \u0434\u043B\u044F \u043A\u0443\u0440\u044C\u0435\u0440\u043E\u0432/\u0442\u0440\u0430\u043D\u0441\u043F\u043E\u0440\u0442\u0430 \u0441 \u0443\u0447\u0451\u0442\u043E\u043C \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u044B\u0445 \u043E\u043A\u043E\u043D (VRPTW), \u0437\u0430\u0433\u0440\u0443\u0437\u043A\u0438 (CVRP), \u043F\u0440\u043E\u0431\u043E\u043A \u0438 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u0439. \u041A\u043B\u0430\u0441\u0441\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u0437\u0430\u0434\u0430\u0447\u0430 VRP (Vehicle Routing Problem) \u043D\u0430 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0435: \u043A\u043B\u0430\u0441\u0442\u0435\u0440\u0438\u0437\u0430\u0446\u0438\u044F \u0437\u0430\u043A\u0430\u0437\u043E\u0432 \u2192 \u043F\u043E\u0441\u0442\u0440\u043E\u0435\u043D\u0438\u0435 \u043C\u0430\u0440\u0448\u0440\u0443\u0442\u0430 (solver) \u2192 \u0440\u0435\u0431\u0430\u043B\u0430\u043D\u0441\u0438\u0440\u043E\u0432\u043A\u0430 \u0432 \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u043C \u0432\u0440\u0435\u043C\u0435\u043D\u0438 (dynamic VRP). \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442 \u0431\u0438\u0437\u043D\u0435\u0441-\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u044F (\u0432\u0435\u0441, \u043E\u0431\u044A\u0451\u043C, \u0432\u0440\u0435\u043C\u044F, \u0442\u0438\u043F \u0430\u0432\u0442\u043E), \u0432\u044B\u0431\u0438\u0440\u0430\u0435\u0442 solver (OR-Tools, Routific, \u042F\u043D\u0434\u0435\u043A\u0441.\u041C\u0430\u0440\u0448\u0440\u0443\u0442\u0438\u0437\u0430\u0446\u0438\u044F) \u0438 \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u0443\u0435\u0442 \u043C\u0435\u0442\u0440\u0438\u043A\u0438 (on-time rate, fill rate, cost per delivery).","permalink":"/sysanalyst-kb.github.io/docs/specialization/logistics-routing"},{"id":"specialization/industry-analytics","title":"\u041E\u0442\u0440\u0430\u0441\u043B\u0435\u0432\u0430\u044F \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0430 (FinTech, Retail, Logistics)","description":"\u0421\u0438\u0441\u0442\u0435\u043C\u043D\u044B\u0439 \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043E\u0431\u044B\u0447\u043D\u043E \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u043D\u0435 \u0432 \u0432\u0430\u043A\u0443\u0443\u043C\u0435, \u0430 \u0432 \u043A\u043E\u043D\u043A\u0440\u0435\u0442\u043D\u043E\u0439 \u043E\u0442\u0440\u0430\u0441\u043B\u0438. \u0420\u0430\u0437\u043D\u044B\u0435 \u043E\u0442\u0440\u0430\u0441\u043B\u0438 \u0438\u043C\u0435\u044E\u0442 \u0440\u0430\u0437\u043D\u0443\u044E \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u043A\u0443: \u0442\u0435\u0440\u043C\u0438\u043D\u043E\u043B\u043E\u0433\u0438\u044E, \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u044B, \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u044F \u043A \u0441\u0438\u0441\u0442\u0435\u043C\u0435, \u0440\u0435\u0433\u0443\u043B\u044F\u0446\u0438\u044E.","permalink":"/sysanalyst-kb.github.io/docs/specialization/industry-analytics"},{"id":"specialization/logistics-wms","title":"\u0421\u043A\u043B\u0430\u0434\u0441\u043A\u0430\u044F \u043B\u043E\u0433\u0438\u0441\u0442\u0438\u043A\u0430 \u0438 WMS","description":"WMS (Warehouse Management System) \u2014 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u043E\u043D\u043D\u0430\u044F \u0441\u0438\u0441\u0442\u0435\u043C\u0430 \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F \u0441\u043A\u043B\u0430\u0434\u043E\u043C \u0442\u0438\u043F\u044B \u0441\u043A\u043B\u0430\u0434\u043E\u0432 (FBO, FBS, DBS, \u043A\u0440\u043E\u0441\u0441-\u0434\u043E\u043A), \u0437\u043E\u043D\u044B \u0441\u043A\u043B\u0430\u0434\u0430, \u0441\u0442\u0430\u0442\u0443\u0441\u044B \u0442\u043E\u0432\u0430\u0440\u0430, \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u0438 \u0441 TMS/OMS. \u041F\u0440\u0438\u043C\u0435\u0440\u044B WMSWMS, Korber.","permalink":"/sysanalyst-kb.github.io/docs/specialization/logistics-wms"},{"id":"specialization/ecommerce-fulfillment","title":"\u0424\u0443\u043B\u0444\u0438\u043B\u043C\u0435\u043D\u0442 \u0438 \u043B\u043E\u0433\u0438\u0441\u0442\u0438\u043A\u0430 e-commerce","description":"\u0424\u0443\u043B\u0444\u0438\u043B\u043C\u0435\u043D\u0442 \u2014 \u0432\u0441\u0451, \u0447\u0442\u043E \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0441 \u0437\u0430\u043A\u0430\u0437\u043E\u043C \u043F\u043E\u0441\u043B\u0435 \u043E\u043F\u043B\u0430\u0442\u044B WMS (\u0441\u043A\u043B\u0430\u0434) \u0438 TMS (\u0442\u0440\u0430\u043D\u0441\u043F\u043E\u0440\u0442). \u0418\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u044F D1 (\u0441\u0435\u0433\u043E\u0434\u043D\u044F), D2 (\u0437\u0430\u0432\u0442\u0440\u0430), D3+ (\u0434\u043E 7 \u0434\u043D\u0435\u0439). Last-mile \u2014 \u0434\u043E 60% \u0441\u0442\u043E\u0438\u043C\u043E\u0441\u0442\u0438 \u0434\u043E\u0441\u0442\u0430\u0432\u043A\u0438. \u0412\u043E\u0437\u0432\u0440\u0430\u0442\u044B \u2014 \u0434\u043E 15% \u0432 fashion.","permalink":"/sysanalyst-kb.github.io/docs/specialization/ecommerce-fulfillment"},{"id":"specialization/logistics-edo","title":"\u042D\u0414\u041E \u0438 \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u043E\u043E\u0431\u043E\u0440\u043E\u0442 \u0432 \u043B\u043E\u0433\u0438\u0441\u0442\u0438\u043A\u0435","description":"\u042D\u0414\u041E (\u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u044B\u0439 \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u043E\u043E\u0431\u043E\u0440\u043E\u0442) \u0432 \u043B\u043E\u0433\u0438\u0441\u0442\u0438\u043A\u0435 \u2014 \u043E\u0431\u043C\u0435\u043D \u0423\u041F\u0414, \u0430\u043A\u0442\u0430\u043C\u0438, \u0441\u0447\u0435\u0442\u0430\u043C\u0438-\u0444\u0430\u043A\u0442\u0443\u0440\u0430\u043C\u0438, \u0442\u0440\u0430\u043D\u0441\u043F\u043E\u0440\u0442\u043D\u044B\u043C\u0438 \u043D\u0430\u043A\u043B\u0430\u0434\u043D\u044B\u043C\u0438 \u043C\u0435\u0436\u0434\u0443 \u0443\u0447\u0430\u0441\u0442\u043D\u0438\u043A\u0430\u043C\u0438 (\u0433\u0440\u0443\u0437\u043E\u043E\u0442\u043F\u0440\u0430\u0432\u0438\u0442\u0435\u043B\u044C, \u043F\u0435\u0440\u0435\u0432\u043E\u0437\u0447\u0438\u043A, \u0433\u0440\u0443\u0437\u043E\u043F\u043E\u043B\u0443\u0447\u0430\u0442\u0435\u043B\u044C). \u0421 2021 \u0433\u043E\u0434\u0430 \u042D\u0422\u0420\u041D (\u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u0430\u044F \u0442\u0440\u0430\u043D\u0441\u043F\u043E\u0440\u0442\u043D\u0430\u044F \u043D\u0430\u043A\u043B\u0430\u0434\u043D\u0430\u044F) \u043E\u0431\u044F\u0437\u0430\u0442\u0435\u043B\u044C\u043D\u0430 \u0434\u043B\u044F \u0433\u0440\u0443\u0437\u043E\u043F\u0435\u0440\u0435\u0432\u043E\u0437\u043E\u043A \u0432 \u0420\u0424. \u0423\u0447\u0430\u0441\u0442\u043D\u0438\u043A\u0438 \u043F\u043E\u0434\u043F\u0438\u0441\u044B\u0432\u0430\u044E\u0442 \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u044B \u0423\u041A\u042D\u041F (\u0443\u0441\u0438\u043B\u0435\u043D\u043D\u0430\u044F \u043A\u0432\u0430\u043B\u0438\u0444\u0438\u0446\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u0430\u044F \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u0430\u044F \u043F\u043E\u0434\u043F\u0438\u0441\u044C) \u0447\u0435\u0440\u0435\u0437 \u043E\u043F\u0435\u0440\u0430\u0442\u043E\u0440\u043E\u0432 \u042D\u0414\u041E (\u0414\u0438\u0430\u0434\u043E\u043A, \u0421\u0411\u0418\u0421, \u041A\u043E\u043D\u0442\u0443\u0440). \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u0443\u0435\u0442 \u0442\u0438\u043F\u044B \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u043E\u0432, \u0441\u0442\u0430\u0442\u0443\u0441\u043D\u0443\u044E \u043C\u043E\u0434\u0435\u043B\u044C, \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u044E \u0441 \u043E\u043F\u0435\u0440\u0430\u0442\u043E\u0440\u0430\u043C\u0438 \u0438 TMS.","permalink":"/sysanalyst-kb.github.io/docs/specialization/logistics-edo"}],"unlisted":false}}')}}]);